```java
import java.util.*;

public class Solution {
    public static long solve(long[][] grid, long k) {
        int m = grid.length;
        int n = grid[0].length;

        // Precompute teleport lists
        List<List<int[]>> teleportList = new ArrayList<>();
        for (int i = 0; i < m; i++) {
            teleportList.add(new ArrayList<>());
            for (int j = 0; j < n; j++) {
                List<int[]> list = new ArrayList<>();
                for (int x = 0; x < m; x++) {
                    for (int y = 0; y < n; y++) {
                        if (grid[x][y] <= grid[i][j]) {
                            list.add(new int[]{x, y});
                        }
                    }
                }
                teleportList.get(i).add(list);
            }
        }

        // Dijkstra's algorithm
        long INF = Long.MAX_VALUE;
        long[][][] dist = new long[m][n][k + 1];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                for (int t = 0; t <= k; t++) {
                    dist[i][j][t] = INF;
                }
            }
        }
        dist[0][0][0] = 0;

        // Priority queue: [cost, i, j, t]
        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));

        pq.offer(new long[]{0, 0, 0, 0});

        int[][] directions = {{0, 1}, {1, 0}}; // right, down

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long cost = current[0];
            int i = current[1];
            int j = current[2];
            int t = current[3];

            if (i == m - 1 && j == n - 1) {
                return cost;
            }

            // Regular moves
            for (int[] dir : directions) {
                int ni = i + dir[0];
                int nj = j + dir[1];
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    long newCost = cost + grid[ni][nj];
                    if (newCost < dist[ni][nj][t]) {
                        dist[ni][nj][t] = newCost;
                        pq.offer(new long[]{newCost, ni, nj, t});
                    }
                }
            }

            // Teleportation
            if (t < k) {
                List<int[]> teleports = teleportList.get(i).get(j);
                for (int[] xy : teleports) {
                    int x = xy[0];
                    int y = xy[1];
                    if (cost < dist[x][y][t + 1]) {
                        dist[x][y][t + 1] = cost;
                        pq.offer(new long[]{cost, x, y, t + 1});
                    }
                }
            }
        }

        // If not found (should not happen)
        return -1;
    }
}
