    const n = grid[0].length;

    // Precompute teleport lists
    const teleportList: Array<Array<[number, number]>> = [];
    for (let i = 0; i < m; i++) {
        teleportList[i] = [];
        for (let j = 0; j < n; j++) {
            teleportList[i][j] = [];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= grid[i][j]) {
                        teleportList[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    // Dijkstra's algorithm
    const INF = Infinity;
    const dist = new Array(m).fill(0).map(() => new Array(n).fill(0).map(() => new Array(k + 1).fill(INF)));
    dist[0][0][0] = 0;

    // Priority queue: [cost, i, j, t]
    const pq: [number, number, number, number][] = [[0, 0, 0, 0]];
    const directions = [[0, 1], [1, 0]]; // right, down

    // Min-heap implementation
    function push(heap: [number, number, number, number][], cost: number, i: number, j: number, t: number) {
        heap.push([cost, i, j, t]);
        heap.sort((a, b) => a[0] - b[0]);
    }

    function pop(heap: [number, number, number, number][]): [number, number, number, number] | undefined {
        if (heap.length === 0) return undefined;
        return heap.shift();
    }

    while (pq.length > 0) {
        const [cost, i, j, t] = pop(pq)!;
        if (i === m - 1 && j === n - 1) return cost;

        // Regular moves
        for (const [dx, dy] of directions) {
            const ni = i + dx;
            const nj = j + dy;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                const newCost = cost + grid[ni][nj];
                if (newCost < dist[ni][nj][t]) {
                    dist[ni][nj][t] = newCost;
                    push(pq, newCost, ni, nj, t);
                }
            }
        }

        // Teleportation
        if (t < k) {
            for (const [x, y] of teleportList[i][j]) {
                const newT = t + 1;
                if (cost < dist[x][y][newT]) {
                    dist[x][y][newT] = cost;
                    push(pq, cost, x, y, newT);
                }
            }
        }
    }

    // If not found (should not happen as per problem constraints)
    return -1;
}
