import java.util.ArrayList;
import java.util.List;
import java.util.PriorityQueue;

public class Solution {
    public static long solve(long[][] grid, long k) {
        int m = grid.length;
        int n = grid[0].length;

        // Precompute teleport lists
        List<List<int[]>> teleportList = new ArrayList<>();
        for (int i = 0; i < m; i++) {
            teleportList.add(new ArrayList<>());
            for (int j = 0; j < n; j++) {
                List<int[]> list = new ArrayList<>();
                for (int x = 0; x < m; x++) {
                    for (int y = 0; y < n; y++) {
                        if (grid[x][y] <= grid[i][j]) {
                            list.add(new int[]{x, y});
                        }
                    }
                }
                teleportList.get(i).add(list);
            }
        }

        // Initialize distance array
        long[][][] dist = new long[m][n][k + 1];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                for (int t = 0; t <= k; t++) {
                    dist[i][j][t] = Long.MAX_VALUE;
                }
            }
        }
        dist[0][0][0] = 0;

        // Priority queue
        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.offer(new long[]{0, 0, 0, 0});

        // Directions: right, down
        int[][] directions = {{0, 1}, {1, 0}};

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long cost = current[0];
            int i = current[1];
            int j = current[2];
            int t = current[3];

            // Check if destination
            if (i == m - 1 && j == n - 1) {
                return cost;
            }

            // Regular moves
            for (int[] dir : directions) {
                int ni = i + dir[0];
                int nj = j + dir[1];
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    long newCost = cost + grid[ni][nj];
                    if (newCost < dist[ni][nj][t]) {
                        dist[ni][nj][t] = newCost;
                        pq.offer(new long[]{newCost, ni, nj, t});
                    }
                }
            }

            // Teleportation
            if (t < k) {
                List<int[]> list = teleportList.get(i).get(j);
                for (int[] coord : list) {
                    int x = coord[0];
                    int y = coord[1];
                    long newT = t + 1;
                    if (cost < dist[x][y][newT]) {
                        dist[x][y][newT] = cost;
                        pq.offer(new long[]{cost, x, y, newT});
                    }
                }
            }
        }

        return -1;
    }
}
