import java.util.ArrayList;
import java.util.PriorityQueue;

public class Solution {
    public static long solve(long[][] grid, long k) {
        int m = grid.length;
        int n = grid[0].length;
        ArrayList<ArrayList<int[]>> teleportList = new ArrayList<>();
        for (int i = 0; i < m; i++) {
            teleportList.add(new ArrayList<>());
            for (int j = 0; j < n; j++) {
                ArrayList<int[]> list = new ArrayList<>();
                for (int x = 0; x < m; x++) {
                    for (int y = 0; y < n; y++) {
                        if (grid[x][y] <= grid[i][j]) {
                            list.add(new int[]{x, y});
                        }
                    }
                }
                teleportList.get(i).add(list);
            }
        }

        long INF = Long.MAX_VALUE;
        long[][][] dist = new long[m][n][k + 1];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                for (int t = 0; t <= k; t++) {
                    dist[i][j][t] = INF;
                }
            }
        }
        dist[0][0][0] = 0;

        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.offer(new long[]{0, 0, 0, 0});

        int[] dx = {0, 1};
        int[] dy = {1, 0};

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long cost = current[0];
            int i = current[1];
            int j = current[2];
            int t = current[3];

            if (i == m - 1 && j == n - 1) {
                return cost;
            }

            for (int d = 0; d < 2; d++) {
                int ni = i + dx[d];
                int nj = j + dy[d];
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    long newCost = cost + grid[ni][nj];
                    if (newCost < dist[ni][nj][t]) {
                        dist[ni][nj][t] = newCost;
                        pq.offer(new long[]{newCost, ni, nj, t});
                    }
                }
            }

            if (t < k) {
                for (int[] xy : teleportList.get(i).get(j)) {
                    int x = xy[0];
                    int y = xy[1];
                    if (cost < dist[x][y][t + 1]) {
                        dist[x][y][t + 1] = cost;
                        pq.offer(new long[]{cost, x, y, t + 1});
                    }
                }
            }
        }

        return -1;
    }
}
